#include <numeric>
#include <bits/stdc++.h>
using namespace std;
struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};
class Solution {
public:
    int lowestCommonAncestor(TreeNode* root, int p, int q) {
        if (!root) return 0;
        if (root->val > p && root->val > q) return lowestCommonAncestor(root->left, p, q);
        if (root->val < p && root->val < q) return lowestCommonAncestor(root->right, p, q);
        return root->val;
    }
};
int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    cin >> n;
    vector<int> node_values(n), left_children(n), right_children(n);
    for (int i = 0; i < n; i++) cin >> node_values[i] >> left_children[i] >> right_children[i];
    int p, q;
    cin >> p >> q;
    Solution sol;
    vector<TreeNode*> nodes_list(n);
    for (int i = 0; i < n; i++) nodes_list[i] = new TreeNode(node_values[i]);
    for (int i = 0; i < n; i++) {
        if (left_children[i] != -1) nodes_list[i]->left = nodes_list[left_children[i]];
        if (right_children[i] != -1) nodes_list[i]->right = nodes_list[right_children[i]];
    }
    TreeNode* root = nodes_list[0];
    cout << sol.lowestCommonAncestor(root, p, q) << '\n';
    return 0;
}
